//! Spec-compliance tests: Fields Deep (ISO 29500-1 §17.16, §17.3.3)
//!
//! These tests audit additional field types (PAGE, DATE, SEQ, STYLEREF,
//! nested complex fields) and special inline content (w:sym, w:noBreakHyphen,
//! w:softHyphen, w:cr, w:lastRenderedPageBreak).
//!
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{CanonDoc, FieldData, FieldKind, InlineNode, OpaqueKind};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/fields-deep";

// -- helpers ----------------------------------------------------------------
/// Collect all FieldData from OpaqueInline nodes in a paragraph's segments.
fn collect_field_opaques(para: &stemma::ParagraphNode) -> Vec<&FieldData> {
    let mut fields = Vec::new();
    for inline in para.all_inlines() {
        if let InlineNode::OpaqueInline(opaque) = inline
            && let OpaqueKind::Field(ref fd) = opaque.kind
        {
            fields.push(fd);
        }
    }
    fields
}

/// Collect all FieldData across all paragraphs.
fn collect_all_fields(doc: &CanonDoc) -> Vec<&FieldData> {
    let mut fields = Vec::new();
    for para in common::all_paragraphs(doc) {
        fields.extend(collect_field_opaques(para));
    }
    fields
}

// -- PAGE / NUMPAGES field tests --------------------------------------------

/// ISO 29500-1 §17.16.19: PAGE field in fldSimple should be captured.
///
/// PAGE is the most common field in real documents (headers/footers).
/// It should produce a FieldKind::Simple with instruction containing "PAGE".
#[test]
fn spec_page_field_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "page-number-field");

    let fields = collect_all_fields(&doc);
    let page_fields: Vec<&&FieldData> = fields
        .iter()
        .filter(|fd| {
            fd.field_kind == FieldKind::Simple
                && fd
                    .instruction_text
                    .as_deref()
                    .is_some_and(|t| t.contains("PAGE") && !t.contains("NUMPAGES"))
        })
        .collect();

    assert!(
        !page_fields.is_empty(),
        "should find at least one PAGE field. All fields: {:?}",
        fields
    );

    let fd = page_fields[0];
    assert_eq!(fd.field_kind, FieldKind::Simple);
    assert!(
        fd.result_text.as_deref().is_some(),
        "PAGE field should have result_text (cached page number)"
    );
}

/// ISO 29500-1 §17.16.19: NUMPAGES field should also be captured alongside PAGE.
#[test]
fn spec_numpages_field_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "page-number-field");

    let fields = collect_all_fields(&doc);
    let numpages_fields: Vec<&&FieldData> = fields
        .iter()
        .filter(|fd| {
            fd.field_kind == FieldKind::Simple
                && fd
                    .instruction_text
                    .as_deref()
                    .is_some_and(|t| t.contains("NUMPAGES"))
        })
        .collect();

    assert!(
        !numpages_fields.is_empty(),
        "should find at least one NUMPAGES field. All fields: {:?}",
        fields
    );
}

// -- DATE field tests -------------------------------------------------------

/// ISO 29500-1 §17.16.5.13: DATE field should be preserved with instruction text.
///
/// The instruction text should contain "DATE" and the format switch.
#[test]
fn spec_date_field_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "date-field");

    let fields = collect_all_fields(&doc);
    let date_fields: Vec<&&FieldData> = fields
        .iter()
        .filter(|fd| {
            fd.field_kind == FieldKind::Simple
                && fd
                    .instruction_text
                    .as_deref()
                    .is_some_and(|t| t.contains("DATE"))
        })
        .collect();

    assert!(
        !date_fields.is_empty(),
        "should find a DATE field. All fields: {:?}",
        fields
    );

    let fd = date_fields[0];
    let instr = fd.instruction_text.as_deref().unwrap();
    assert!(
        instr.contains("yyyy"),
        "DATE field instruction should contain format switch, got: {instr:?}"
    );
}

/// ISO 29500-1 §17.16.5.13: DATE field should have cached result text.
#[test]
fn spec_date_field_result_text() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "date-field");

    let fields = collect_all_fields(&doc);
    let date_field = fields
        .iter()
        .find(|fd| {
            fd.field_kind == FieldKind::Simple
                && fd
                    .instruction_text
                    .as_deref()
                    .is_some_and(|t| t.contains("DATE"))
        })
        .expect("should find a DATE field");

    let result = date_field
        .result_text
        .as_deref()
        .expect("DATE field should have result_text with cached date value");
    assert!(
        result.contains("2025"),
        "result text should contain '2025', got: {result:?}"
    );
}

