/// ISO 29500-1 §17.16.5.56: SEQ fields should be captured with instruction text.
///
/// Two SEQ fields in separate paragraphs should each produce FieldKind::Simple.
#[test]
fn spec_seq_field_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "seq-field");

    let fields = collect_all_fields(&doc);
    let seq_fields: Vec<&&FieldData> = fields
        .iter()
        .filter(|fd| {
            fd.field_kind == FieldKind::Simple
                && fd
                    .instruction_text
                    .as_deref()
                    .is_some_and(|t| t.contains("SEQ"))
        })
        .collect();

    assert!(
        seq_fields.len() >= 2,
        "should find at least 2 SEQ fields (Figure 1 and Figure 2), got {}. All fields: {:?}",
        seq_fields.len(),
        fields
    );
}

/// ISO 29500-1 §17.16.5.56: SEQ fields should have sequential result values.
#[test]
fn spec_seq_field_result_values() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "seq-field");

    let fields = collect_all_fields(&doc);
    let seq_fields: Vec<&&FieldData> = fields
        .iter()
        .filter(|fd| {
            fd.field_kind == FieldKind::Simple
                && fd
                    .instruction_text
                    .as_deref()
                    .is_some_and(|t| t.contains("SEQ"))
        })
        .collect();

    assert!(seq_fields.len() >= 2, "need at least 2 SEQ fields");

    let r1 = seq_fields[0]
        .result_text
        .as_deref()
        .expect("first SEQ should have result_text");
    let r2 = seq_fields[1]
        .result_text
        .as_deref()
        .expect("second SEQ should have result_text");

    assert_eq!(r1, "1", "first SEQ result should be '1', got {r1:?}");
    assert_eq!(r2, "2", "second SEQ result should be '2', got {r2:?}");
}

// -- nested complex field tests ---------------------------------------------

/// ISO 29500-1 §17.16.18: Nested fields should maintain begin/end structure.
///
/// An IF field containing a REF field should produce fldChar opaques for
/// both the outer and inner field boundaries.
#[test]
fn spec_nested_field_structure() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-field-nested");

    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");
    let fields = collect_field_opaques(para);

    // Count begin and end markers — nested fields produce 2 of each
    let begin_count = fields
        .iter()
        .filter(|fd| fd.field_kind == FieldKind::Begin)
        .count();
    let end_count = fields
        .iter()
        .filter(|fd| fd.field_kind == FieldKind::End)
        .count();

    assert!(
        begin_count >= 2,
        "nested fields should produce at least 2 Begin markers, got {begin_count}. Fields: {:?}",
        fields.iter().map(|fd| &fd.field_kind).collect::<Vec<_>>()
    );
    assert!(
        end_count >= 2,
        "nested fields should produce at least 2 End markers, got {end_count}. Fields: {:?}",
        fields.iter().map(|fd| &fd.field_kind).collect::<Vec<_>>()
    );
}

/// ISO 29500-1 §17.16.18: Both instruction texts from nested fields should be captured.
///
/// The outer IF instruction and inner REF instruction should both appear.
#[test]
fn spec_nested_field_instructions() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-field-nested");

    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");
    let fields = collect_field_opaques(para);

    let instructions: Vec<&str> = fields
        .iter()
        .filter(|fd| fd.field_kind == FieldKind::Instruction)
        .filter_map(|fd| fd.instruction_text.as_deref())
        .collect();

    let has_if = instructions.iter().any(|t| t.contains("IF"));
    let has_ref = instructions.iter().any(|t| t.contains("REF"));

    assert!(
        has_if,
        "should find IF instruction text. Instructions: {instructions:?}"
    );
    assert!(
        has_ref,
        "should find REF instruction text. Instructions: {instructions:?}"
    );
}

