// -- special character tests ------------------------------------------------

/// ISO 29500-1 §17.3.3.30: w:sym should produce an OpaqueInline with Sym variant.
///
/// The sym element represents a symbol character from a specific font. It is
/// classified as a run widget and promoted to OpaqueKind::Sym with decoded
/// font/char data.
#[test]
fn spec_special_chars_sym() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "special-characters");

    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");

    let sym_data = para.all_inlines().find_map(|inline| {
        if let InlineNode::OpaqueInline(opaque) = inline {
            if let OpaqueKind::Sym(data) = &opaque.kind {
                Some(data.clone())
            } else {
                None
            }
        } else {
            None
        }
    });

    let data = sym_data.expect("w:sym should produce an OpaqueInline with OpaqueKind::Sym variant");
    // Verify the sym data was decoded
    assert!(!data.font.is_empty(), "sym font should not be empty");
    assert!(
        !data.char_code.is_empty(),
        "sym char_code should not be empty"
    );
}

/// ISO 29500-1 §17.3.3.18: w:noBreakHyphen should produce an inline node.
///
/// noBreakHyphen is classified as a run decoration in word_ir.rs and becomes
/// an InlineNode::Decoration.
#[test]
fn spec_special_chars_no_break_hyphen() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "special-characters");

    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");

    let has_decoration = para
        .all_inlines()
        .any(|inline| matches!(inline, InlineNode::Decoration(_)));

    assert!(
        has_decoration,
        "w:noBreakHyphen should produce a Decoration inline node"
    );
}

/// ISO 29500-1 §17.3.3.29: w:softHyphen should produce a Decoration inline node.
#[test]
fn spec_special_chars_soft_hyphen() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "special-characters");

    // The fixture contains both noBreakHyphen and softHyphen as decorations.
    // We verify that at least two decoration nodes exist (noBreakHyphen,
    // softHyphen, and lastRenderedPageBreak = 3 total).
    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");

    let decoration_count = para
        .all_inlines()
        .filter(|inline| matches!(inline, InlineNode::Decoration(_)))
        .count();

    assert!(
        decoration_count >= 2,
        "should have at least 2 Decoration nodes (noBreakHyphen + softHyphen), got {decoration_count}"
    );
}

/// ISO 29500-1 §17.3.3.4: w:cr should produce a HardBreak inline node.
///
/// cr (carriage return) is handled the same as br (line break).
#[test]
fn spec_special_chars_cr() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "special-characters");

    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");

    let has_break = para
        .all_inlines()
        .any(|inline| matches!(inline, InlineNode::HardBreak(_)));

    assert!(has_break, "w:cr should produce a HardBreak inline node");
}

/// ISO 29500-1 §17.3.3.13: w:lastRenderedPageBreak should produce a Decoration node.
///
/// lastRenderedPageBreak is classified as a run decoration — a zero-width
/// marker indicating where Word last broke the page.
#[test]
fn spec_special_chars_last_rendered_page_break() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "special-characters");

    let paras = common::all_paragraphs(&doc);
    let para = paras.last().expect("should have at least one paragraph");

    // lastRenderedPageBreak and softHyphen are zero-width decorations. noBreakHyphen
    // is NOT a decoration — it is a visible character (§17.3.3.18), modeled as
    // AtomKind::NoBreakHyphen and projected to U+2011 in the read text.
    // So we expect at least 2 decorations plus a U+2011 text character.
    let decoration_count = para
        .all_inlines()
        .filter(|inline| matches!(inline, InlineNode::Decoration(_)))
        .count();
    assert!(
        decoration_count >= 2,
        "should have at least 2 Decoration nodes (softHyphen + lastRenderedPageBreak), got {decoration_count}"
    );

    let has_nbhyphen = para
        .all_inlines()
        .any(|inline| matches!(inline, InlineNode::Text(t) if t.text.contains('\u{2011}')));
    assert!(
        has_nbhyphen,
        "noBreakHyphen must read as a visible U+2011 character (§17.3.3.18), not a zero-width decoration"
    );
}
